import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { useInAppNavigate } from '../../router/useInAppNavigate';

import {
  Select,
  detectDateRangePreset,
  SearchTextInput,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  useViewMobileLayout,
  useServerPagedListLoading,
  ListGridBusyWrap,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import { useProcessingLevelLabels } from '../../hooks/useProcessingLevelLabels';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { ktService } from '../../services/kt/ktService';
import type { CashVoucherDto, CashVoucherPaymentMedium } from '../../services/kt/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
  voucherListRowMenuHintDismissStorageKey,
} from '../../utils/voucherListRowMenuHint';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import { VoucherPrintModal, VoucherPostedLedgerModal } from '../voucher';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list';
import { VoucherListSelectionBanner } from '../voucher-list/VoucherListSelectionBanner';
import { resolveVoucherBatchIds } from '../../utils/resolveVoucherBatchIds';
import { useVoucherListSelection } from '../../hooks/useVoucherListSelection';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../utils/voucherListRowActions';
import { getCashVoucherConfig } from '../../features/kt/cash-voucher/shared/config/cashVoucherConfig';
import {
  defaultShellIdForKind,
  getCashVoucherShellProfile,
  type CashVoucherShellId,
} from '../../features/kt/cash-voucher/shared/config/cashVoucherShellProfiles';
import erp from '../../styles/erpPage.module.css';
import {
  DEFAULT_PAGE_SIZE,
  normalizeListPageSize,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import {
  CatalogListGridFromSchema,
  ListUiSchemaEditorModal,
  listVisibleFields,
  useCatalogUiSchema,
} from '../listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../types/catalogUiSchema';

const PAGE_SIZE = DEFAULT_PAGE_SIZE;
export type CashVoucherKind = 'receipt' | 'payment';

const PAYMENT_MEDIUM_OPTIONS: { value: '' | CashVoucherPaymentMedium; label: string }[] = [
  { value: '', label: 'Tất cả kênh' },
  { value: 'cash', label: 'Tiền mặt (PT1/PC1)' },
  { value: 'bank', label: 'Ngân hàng (BC1/BN1)' },
];

const UNC_CATEGORY_OPTIONS: { value: string; label: string }[] = [
  { value: '', label: 'Tất cả loại UNC' },
  { value: 'bhxh', label: 'Nộp BHXH' },
  { value: 'tax', label: 'Nộp thuế KBNN' },
  { value: 'fee', label: 'Phí ngân hàng' },
  { value: 'internal', label: 'Rút tiền / nội bộ' },
];

function buildListConfig(shellId: CashVoucherShellId, kind: CashVoucherKind) {
  const shell = getCashVoucherShellProfile(shellId);
  const beCfg = getCashVoucherConfig(kind);
  return {
    title: shell.pageTitle,
    listTitle: shell.listTitle,
    pageId: `kt-${shell.voucherRegistryCode}`,
    icon: kind === 'receipt' ? 'fa-file-invoice-dollar' : 'fa-money-bill-wave',
    createPath: shell.createPath,
    createInitFormName: shell.createInitFormName,
    detailPath: shell.detailPath,
    fetch: beCfg.fetch,
    batchUpdateProcessingLevel: kind === 'receipt'
      ? ktService.batchUpdateReceiptProcessingLevel
      : ktService.batchUpdatePaymentProcessingLevel,
    listScope: shell.listScope,
    shell,
  } as const;
}

function isRowSelectable(row: CashVoucherDto): boolean {
  return row.status === 'Draft';
}

function parsePaymentMediumFromSearch(search: string): '' | CashVoucherPaymentMedium {
  const value = new URLSearchParams(search).get('paymentMedium')?.trim().toLowerCase();
  if (value === 'cash' || value === 'bank') return value;
  return '';
}

export const CashVoucherList: React.FC<{ kind: CashVoucherKind; shellId?: CashVoucherShellId }> = ({
  kind,
  shellId,
}) => {
  const resolvedShellId = shellId ?? defaultShellIdForKind(kind);
  const cfg = useMemo(() => buildListConfig(resolvedShellId, kind), [resolvedShellId, kind]);
  const shell = cfg.shell;
  const listFetch = cfg.fetch;
  const voucherShellFilter = shell.voucherShell;
  const beCfg = getCashVoucherConfig(kind);
  const location = useLocation();
  const dispatch = useAppDispatch();
  const navigate = useInAppNavigate();
  const viewMobile = useViewMobileLayout();
  const {
    initialized,
    fromDate,
    toDate,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(cfg.listScope);
  const [items, setItems] = useState<CashVoucherDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(PAGE_SIZE);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [paymentMedium, setPaymentMedium] = useState<'' | CashVoucherPaymentMedium>('');
  const [uncCategory, setUncCategory] = useState('');
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: CashVoucherDto } | null>(null);
  const loadErrorToastShownRef = React.useRef(false);

  useEffect(() => {
    if (shell.lockPaymentMedium) {
      setPaymentMedium(shell.paymentMedium === 'bank' ? 'bank' : '');
      return;
    }
    const fromUrl = parsePaymentMediumFromSearch(location.search);
    setPaymentMedium(fromUrl);
  }, [location.search, shell.lockPaymentMedium, shell.paymentMedium]);

  const listTitle = cfg.listTitle;

  const testIdPrefix = `kt-${shell.voucherRegistryCode}`;
  const uiSchemaKind = kind === 'receipt'
    ? LIST_UI_SCHEMA_KIND.cashReceipt
    : LIST_UI_SCHEMA_KIND.cashPayment;
  const sampleRow = useMemo(
    () => (items[0] ? (items[0] as unknown as Record<string, unknown>) : null),
    [items],
  );
  const { schema, reload: reloadSchema } = useCatalogUiSchema(uiSchemaKind, { sampleRow });
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const { levelOptions, filterOptions, formatLabel } = useProcessingLevelLabels(
    kind,
    cfg.createInitFormName,
    cfg.shell.voucherRegistryCode,
  );
  const {
    formPermissions,
    canCreate,
    canApprove,
    canUpdate,
    canPrint,
    canViewLedger: canViewLedgerPerm,
  } = useVoucherListActions(cfg.createInitFormName);
  void formPermissions;
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const selection = useVoucherListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable,
  });

  const activeRow = selection.activeRow;

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow
    ? canEditFromListRow(activeRow, canUpdate)
    : false;
  const canViewLedgerActive = activeRow
    ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm)
    : false;
  const canPrintActive = Boolean(activeRow) && canPrint;

  const refresh = useCallback(() => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection, setLoadingMode]);

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setLoadingMode('filter');
    setPageSizeState(normalizeListPageSize(size));
    setPage(1);
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      listFetch({
        fromDate,
        toDate,
        search: search || undefined,
        processingLevel: processingLevel || undefined,
        paymentMedium: voucherShellFilter ? undefined : (paymentMedium || undefined),
        voucherShell: voucherShellFilter ?? undefined,
        uncCategory: shell.id === 'uy-nhiem-chi' && uncCategory ? uncCategory : undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (!cancelled) {
            loadErrorToastShownRef.current = false;
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            if (!loadErrorToastShownRef.current) {
              loadErrorToastShownRef.current = true;
              dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải danh sách'), type: 'error' });
            }
            setItems([]);
            setTotalCount(0);
          }
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, fromDate, toDate, search, processingLevel, paymentMedium, uncCategory, page, pageSize, reloadKey, dispatch, listFetch, voucherShellFilter, shell.id, beginFetch, endFetch]);

  const pageSelectableCount = useMemo(
    () => items.filter(isRowSelectable).length,
    [items],
  );

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      const ids = await resolveVoucherBatchIds(
        selection,
        items,
        isRowSelectable,
        (p, ps) => cfg.fetch({
          fromDate,
          toDate,
          search: search || undefined,
          processingLevel: processingLevel || undefined,
          page: p,
          pageSize: ps,
        }),
        totalCount,
      );
      if (ids.length === 0) {
        dispatchAppToast(dispatch, { message: 'Không có chứng từ Nháp hợp lệ để phê duyệt', type: 'warning' });
        return;
      }
      await cfg.batchUpdateProcessingLevel({
        ids,
        processingLevel: newLevel,
      });
      dispatchAppToast(dispatch, { message: 'Phê duyệt thành công', type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const navigateToRow = useCallback((id: string, startInEditMode?: boolean) => {
    navigate(cfg.detailPath(id), {
      state: startInEditMode ? { startInEditMode: true } : undefined,
    });
  }, [navigate, cfg]);

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: CashVoucherDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (canEditFromListRow(row, canUpdate)) {
            navigateToRow(row.id, true);
          }
          break;
        case 'viewLedger':
          if (canViewLedgerFromListRow(row, canViewLedgerPerm)) {
            setShowLedgerModal(true);
          }
          break;
        case 'print':
          if (canPrint) {
            setShowPrintModal(true);
          }
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, canUpdate, canViewLedgerPerm, canPrint, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow ? canEditFromListRow(rowMenuRow, canUpdate) : false;
  const rowMenuViewLedgerDisabled = rowMenuRow
    ? !canViewLedgerFromListRow(rowMenuRow, canViewLedgerPerm)
    : true;
  const rowMenuPrintDisabled = !canPrint;

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix,
      onRefresh: refresh,
      canApprove,
      approveDisabled: selection.selectedCount === 0,
      onApprove: () => setShowApproveModal(true),
      canViewLedger: canViewLedgerActive,
      onViewLedger: () => setShowLedgerModal(true),
      canPrint: canPrintActive,
      onPrint: () => setShowPrintModal(true),
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate,
      onCreate: () => navigate(cfg.createPath),
      onEditConfig: () => setShowSchemaEditor(true),
    }),
    [
      testIdPrefix,
      canApprove,
      selection.selectedCount,
      canViewLedgerActive,
      canPrintActive,
      canViewActive,
      canEditActive,
      canCreate,
      activeRow,
      cfg.createPath,
      refresh,
      navigate,
      navigateToRow,
    ],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={testIdPrefix}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setLoadingMode('filter');
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${testIdPrefix}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder={cfg.shell.listSearchPlaceholder}
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${testIdPrefix}-search-text`}
              />
            </div>
            <div data-testid={`${testIdPrefix}-field-processingLevel`}>
              <Select
                label="Mức xử lý"
                value={processingLevel}
                onChange={e => {
                  setLoadingMode('filter');
                  setProcessingLevel(e.target.value);
                  resetPage();
                }}
                options={filterOptions}
              />
            </div>
            {shell.hidePaymentMediumFilter ? null : (
            <div data-testid={`${testIdPrefix}-field-paymentMedium`}>
              <Select
                label="Kênh TT"
                value={paymentMedium}
                onChange={e => {
                  setLoadingMode('filter');
                  setPaymentMedium(e.target.value as '' | CashVoucherPaymentMedium);
                  resetPage();
                }}
                options={PAYMENT_MEDIUM_OPTIONS}
              />
            </div>
            )}
            {shell.id === 'uy-nhiem-chi' ? (
              <div data-testid={`${testIdPrefix}-field-uncCategory`}>
                <Select
                  label="Loại UNC"
                  value={uncCategory}
                  onChange={e => {
                    setLoadingMode('filter');
                    setUncCategory(e.target.value);
                    resetPage();
                  }}
                  options={UNC_CATEGORY_OPTIONS}
                />
              </div>
            ) : null}
          </>
        )}
      />
    ),
    [
      testIdPrefix,
      searchDraft,
      fromDate,
      toDate,
      processingLevel,
      paymentMedium,
      shell.hidePaymentMediumFilter,
      shell.id,
      uncCategory,
      filterOptions,
      applyDateRange,
      resetPage,
      setProcessingLevel,
      setSearchDraft,
      setLoadingMode,
      handleSearch,
      showTableLoading,
    ],
  );

  const selectionBanner = (
    <VoucherListSelectionBanner
      testIdPrefix={testIdPrefix}
      selectedCount={selection.selectedCount}
      totalCount={totalCount}
      selectionMode={selection.selectionMode}
      pageSelectableCount={pageSelectableCount}
      onSelectAllDatabase={selection.selectAllInDatabase}
      onClear={selection.clearSelection}
    />
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty}>Không có dữ liệu</div>
  ) : !showTableLoading && listColumns.length > 0 ? (
    <ListGridBusyWrap pageLoading={pageLoading}>
      <CatalogListGridFromSchema
        testIdPrefix={testIdPrefix}
        rows={items}
        page={page}
        pageSize={pageSize}
        columns={listColumns}
        schema={schema}
        selection={selection}
        getRowId={r => r.id}
        isRowSelectable={isRowSelectable}
        formatProcessingLevel={formatLabel}
        gridProps={{
          onRowOpenActionMenu: handleRowOpenActionMenu,
          rowMenuHintMessage,
          rowMenuHintDismissStorageKey: voucherListRowMenuHintDismissStorageKey(testIdPrefix),
          enableRowMenuLongPress: viewMobile,
        }}
      />
    </ListGridBusyWrap>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={testIdPrefix}
        pageId={cfg.pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: cfg.title,
          titleIconClass: `fas ${cfg.icon}`,
          pageId: cfg.pageId,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={selectionBanner}
        listTitle={listTitle}
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={(
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        )}
        modals={(
          <>
            <ProcessingLevelApproveModal
              isOpen={showApproveModal}
              onClose={() => setShowApproveModal(false)}
              currentLevel={String(levelOptions[0]?.value ?? '3')}
              levelOptions={levelOptions}
              onConfirm={handleBatchApproveConfirm}
              saving={approving}
              testIdPrefix={testIdPrefix}
            />
            {activeRow && (
              <>
                <VoucherPrintModal
                  isOpen={showPrintModal}
                  onClose={() => setShowPrintModal(false)}
                  voucherTitle={`${cfg.title} — ${activeRow.code}`}
                  onPrint={handlePrintConfirm}
                  printing={printing}
                  testIdPrefix={testIdPrefix}
                />
                <VoucherPostedLedgerModal
                  isOpen={showLedgerModal}
                  onClose={() => setShowLedgerModal(false)}
                  voucherTitle={`${cfg.title} — ${activeRow.code}`}
                  testIdPrefix={testIdPrefix}
                  fetchPostedLedger={() => beCfg.getPostedLedger(activeRow.id)}
                  fetchPostingStatus={() => beCfg.getPostingStatus(activeRow.id)}
                />
              </>
            )}
            <ListUiSchemaEditorModal
              testIdPrefix={testIdPrefix}
              catalogKind={uiSchemaKind}
              sampleRow={sampleRow}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => {
                reloadSchema();
                refresh();
              }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={testIdPrefix}
              showView
              showEdit={rowMenuShowEdit}
              showViewLedger
              showPrint
              viewLedgerDisabled={rowMenuViewLedgerDisabled}
              printDisabled={rowMenuPrintDisabled}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};
